const b = $input.first().json;
function pick(){for(let i=0;i<arguments.length;i++){const k=arguments[i];if(b[k]!==undefined&&b[k]!==null&&b[k]!=='')return b[k];}return '';}
const barcode = String(pick('Tracking / Barcode','barcode','tracking_number')).trim();
const claim_status = String(pick('Evri outcome code','claim_status')).trim();
const settle = pick('Settlement amount','settlement_amount');
const out = { barcode, claim_status };
if (settle !== '' && settle !== undefined && settle !== null) out.settlement_amount = Number(settle);
return [{ json: out }];
